```typescript
import { Effect, Data, pipe } from "effect";

interface User { readonly id: string; readonly teamId: string }
interface Team { readonly id: string; readonly name: string }

class UserNotFound extends Data.TaggedError("UserNotFound")<{ readonly id: string }> {}
class TeamNotFound extends Data.TaggedError("TeamNotFound")<{ readonly id: string }> {}

declare const fetchUser: (id: string) => Effect.Effect<User, UserNotFound>;
declare const fetchTeam: (id: string) => Effect.Effect<Team, TeamNotFound>;

// Flat-map form — reads inside-out on every continuation.
export const loadViaFlatMap = (
  id: string,
): Effect.Effect<{ user: User; team: Team }, UserNotFound | TeamNotFound> =>
  pipe(
    fetchUser(id),
    Effect.flatMap((user) =>
      pipe(
        fetchTeam(user.teamId),
        Effect.map((team) => ({ user, team })),
      ),
    ),
  );

// Gen form — reads top-to-bottom, one `yield*` per step.
export const loadViaGen = (
  id: string,
): Effect.Effect<{ user: User; team: Team }, UserNotFound | TeamNotFound> =>
  Effect.gen(function* () {
    const user = yield* fetchUser(id);
    const team = yield* fetchTeam(user.teamId);
    return { user, team };
  });
```

