import { Effect, pipe } from "effect";

declare const step1: Effect.Effect<number>;
declare const step2: (n: number) => Effect.Effect<string>;
declare const step3: (s: string) => Effect.Effect<boolean>;

// Before — nested continuations.
export const viaFlatMap: Effect.Effect<boolean> = pipe(
  step1,
  Effect.flatMap((n) => step2(n)),
  Effect.flatMap((s) => step3(s)),
);

// After — one yield per step.
export const viaGen: Effect.Effect<boolean> = Effect.gen(function* () {
  const n = yield* step1;
  const s = yield* step2(n);
  const b = yield* step3(s);
  return b;
});
```

`Effect.gen` wins as soon as you have two or more sequential binds — it reads top-to-bottom and keeps intermediate names in scope. `Effect.flatMap` wins when you have exactly one continuation and no intermediate name is useful; a bare `pipe(eff, Effect.flatMap(k))` stays flatter than an anonymous generator for a single bind, and `Effect.map` is even shorter when the continuation is pure.

```typescript
import { Effect, pipe } from "effect";

declare const loadId: Effect.Effect<string>;
declare const loadRecord: (id: string) => Effect.Effect<{ id: string; name: string }>;

// One bind, no intermediate reuse: flatMap is fine.
export const viaFlatMap: Effect.Effect<{ id: string; name: string }> = pipe(
  loadId,
  Effect.flatMap(loadRecord),
);

// Two binds with cross-step access: gen is clearer.
export const viaGen: Effect.Effect<string> = Effect.gen(function* () {
  const id = yield* loadId;
  const rec = yield* loadRecord(id);
  return `${id}:${rec.name}`;
});
