import { Effect, Data, pipe } from "effect";

interface Cart { readonly items: ReadonlyArray<{ price: number; qty: number }> }
interface Charge { readonly id: string; readonly amount: number }

class InvalidCart extends Data.TaggedError("InvalidCart")<{ readonly reason: string }> {}
class ChargeError extends Data.TaggedError("ChargeError")<{ readonly amount: number }> {}

const validate = (c: Cart): Effect.Effect<Cart, InvalidCart> =>
  c.items.length > 0
    ? Effect.succeed(c)
    : Effect.fail(new InvalidCart({ reason: "empty" }));

const total = (c: Cart): Effect.Effect<number> =>
  Effect.succeed(c.items.reduce((s, i) => s + i.price * i.qty, 0));

declare const charge: (amount: number) => Effect.Effect<Charge, ChargeError>;

export const checkoutViaPipe = (c: Cart): Effect.Effect<Charge, InvalidCart | ChargeError> =>
  pipe(
    validate(c),
    Effect.flatMap(total),
    Effect.flatMap(charge),
  );

export const checkoutViaGen = (c: Cart): Effect.Effect<Charge, InvalidCart | ChargeError> =>
  Effect.gen(function* () {
    const v = yield* validate(c);
    const amount = yield* total(v);
    return yield* charge(amount);
  });
