Reach for `chain` when the next step depends on the previous value — the second computation cannot be described until the first succeeds. Reach for `ap` (or the record-based `apS` / `sequenceS`) when the steps are independent and you only want to combine their results: parsing two fields of a form, validating two flags, combining two queries. With `chain` you get short-circuit on first failure; with an accumulating applicative you can collect all the failures.

```typescript
import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Form { name: string; age: number }

const parseName = (raw: string): E.Either<string, string> =>
  raw.trim().length > 0 ? E.right(raw.trim()) : E.left("name empty");

const parseAge = (raw: string): E.Either<string, number> => {
  const n = Number.parseInt(raw, 10);
  return Number.isFinite(n) && n >= 0 ? E.right(n) : E.left("age invalid");
};

// ap — independent fields, combined only when both succeed.
export const buildForm = (nameRaw: string, ageRaw: string): E.Either<string, Form> =>
  pipe(
    parseName(nameRaw),
    E.map((name) => (age: number): Form => ({ name, age })),
    E.ap(parseAge(ageRaw)),
  );

// chain — dependent step: check age only if name was a known admin.
export const adminOnly = (nameRaw: string, ageRaw: string): E.Either<string, Form> =>
  pipe(
    parseName(nameRaw),
    E.chain((name) =>
      name === "root"
        ? pipe(parseAge(ageRaw), E.map((age) => ({ name, age })))
        : E.left("not admin"),
    ),
  );
```

