import { pipe } from "fp-ts/function";
import * as O from "fp-ts/Option";

// Functor — map transforms the value if present.
export const doubled = (n: O.Option<number>): O.Option<number> =>
  pipe(n, O.map((x) => x * 2));

// Applicative — combine two independent options into one.
export const sum2 = (a: O.Option<number>, b: O.Option<number>): O.Option<number> =>
  pipe(
    a,
    O.map((x) => (y: number) => x + y),
    O.ap(b),
  );

// Monad — second step depends on the first value.
export const divide = (num: O.Option<number>, den: O.Option<number>): O.Option<number> =>
  pipe(
    num,
    O.chain((n) =>
      pipe(
        den,
        O.chain((d) => (d === 0 ? O.none : O.some(n / d))),
      ),
    ),
  );
```

