import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";
import { sequenceT } from "fp-ts/Apply";

type Err = string;

const r1: E.Either<Err, number> = E.right(1);
const r2: E.Either<Err, number> = E.right(2);
const r3: E.Either<Err, number> = E.right(3);

// sequenceT — independent values, collapse to a tuple; first failure wins here
// because we use the default Either applicative (not the validation variant).
export const triple: E.Either<Err, readonly [number, number, number]> =
  sequenceT(E.Apply)(r1, r2, r3);

// chain — only reach the third call if the earlier ones succeeded AND you need
// their value to build the next step.
export const dependent: E.Either<Err, number> = pipe(
  r1,
  E.chain((a) =>
    pipe(
      r2,
      E.chain((b) => (a + b > 0 ? r3 : E.left("early exit"))),
    ),
  ),
);
