A Kleisli arrow is a function `A -> M<B>` for some effectful `M`. Plain `compose` gives you `(g . f) a = g(f(a))`, but once `f` returns an `M<B>` that no longer type-checks — `g` wants `B`, not `M<B>`. The fix is monadic composition: run `f`, flatMap the result into `g`. In Effect v3 the combinator is `Effect.flatMap`; threading `pipe(a, f, Effect.flatMap(g))` is the canonical Kleisli composition.

```typescript
import { Effect, pipe } from "effect";

type Kleisli<A, B, E = never, R = never> = (a: A) => Effect.Effect<B, E, R>;

export const composeK = <A, B, C, E1, E2, R1, R2>(
  f: Kleisli<A, B, E1, R1>,
  g: Kleisli<B, C, E2, R2>,
): Kleisli<A, C, E1 | E2, R1 | R2> =>
  (a) => pipe(f(a), Effect.flatMap(g));

declare const parseId: Kleisli<string, number, "bad-id">;
declare const loadRow: Kleisli<number, { name: string }, "not-found">;

export const parseAndLoad: Kleisli<string, { name: string }, "bad-id" | "not-found"> =
  composeK(parseId, loadRow);
```

