import { pipe } from "fp-ts/function";
import * as TE from "fp-ts/TaskEither";

type Err = { tag: "BadUrl" } | { tag: "HttpError"; status: number } | { tag: "BadJson" };

const parseUrl = (raw: string): TE.TaskEither<Err, URL> =>
  TE.tryCatch(
    async () => new URL(raw),
    (): Err => ({ tag: "BadUrl" }),
  );

const fetchBody = (u: URL): TE.TaskEither<Err, string> =>
  TE.tryCatch(
    async () => {
      const r = await fetch(u.toString());
      if (!r.ok) throw { tag: "HttpError", status: r.status } as const;
      return r.text();
    },
    (e): Err => (typeof e === "object" && e !== null && "tag" in e ? (e as Err) : { tag: "HttpError", status: 0 }),
  );

const parseJson = (body: string): TE.TaskEither<Err, unknown> =>
  TE.tryCatch(
    async () => JSON.parse(body) as unknown,
    (): Err => ({ tag: "BadJson" }),
  );

// Kleisli composition: each chain takes the previous success into the next arrow.
export const loadJson = (raw: string): TE.TaskEither<Err, unknown> =>
  pipe(parseUrl(raw), TE.chain(fetchBody), TE.chain(parseJson));
```

