import { Effect, pipe } from "effect";

// Kleisli identity: A -> Effect<A>.
export const idK = <A>(a: A): Effect.Effect<A> => Effect.succeed(a);

// Kleisli compose.
const composeK = <A, B, C, E1, E2>(
  f: (a: A) => Effect.Effect<B, E1>,
  g: (b: B) => Effect.Effect<C, E2>,
) => (a: A): Effect.Effect<C, E1 | E2> => pipe(f(a), Effect.flatMap(g));

// Laws: composeK(idK, f) === f and composeK(f, idK) === f (up to Effect equivalence).
declare const f: (s: string) => Effect.Effect<number, "E">;

export const leftIdentity = composeK(idK<string>, f);   // (s) => f(s)
export const rightIdentity = composeK(f, idK<number>);  // (s) => f(s)
```

