import { pipe } from "fp-ts/function";

interface Lens<S, A> {
  readonly get: (s: S) => A;
  readonly set: (a: A) => (s: S) => S;
}

const prop =
  <S>() =>
  <K extends keyof S>(k: K): Lens<S, S[K]> => ({
    get: (s) => s[k],
    set: (v) => (s) => ({ ...s, [k]: v }),
  });

const compose =
  <S, A, B>(outer: Lens<S, A>, inner: Lens<A, B>): Lens<S, B> => ({
    get: (s) => inner.get(outer.get(s)),
    set: (b) => (s) => outer.set(inner.set(b)(outer.get(s)))(s),
  });

interface Address { readonly street: string; readonly city: string }
interface User { readonly id: string; readonly address: Address }

const address = prop<User>()("address");
const city = prop<Address>()("city");
const userCity = compose(address, city);

const alice: User = { id: "u1", address: { street: "1 Way", city: "NYC" } };

export const aliceCity: string = userCity.get(alice);
export const alicePGH: User = pipe(alice, userCity.set("PGH"));
```

