export const uploadAll = (
  files: ReadonlyArray<File>,
): Effect.Effect<{ ids: ReadonlyArray<string>; errors: ReadonlyArray<UploadError> }> =>
  pipe(
    Effect.partition(files, uploadOne, { concurrency: 4 }),
    Effect.map(([errors, ids]) => ({ ids, errors })),
  );
