import * as RTE from "fp-ts/ReaderTaskEither";
import * as TE from "fp-ts/TaskEither";

interface Deps { readonly log: (msg: string) => void; readonly baseUrl: string }
type E = { readonly tag: "FetchError"; readonly msg: string };

const getJson = (path: string): RTE.ReaderTaskEither<Deps, E, unknown> =>
  (deps) =>
    TE.tryCatch(
      async () => {
        deps.log(`GET ${deps.baseUrl}${path}`);
        const r = await fetch(`${deps.baseUrl}${path}`);
        return (await r.json()) as unknown;
      },
      (u): E => ({ tag: "FetchError", msg: u instanceof Error ? u.message : String(u) }),
    );

export const status: RTE.ReaderTaskEither<Deps, E, unknown> = pipe(
  getJson("/status"),
  RTE.map((j) => j),
);
