import { pipe } from "fp-ts/function";
import * as RTE from "fp-ts/ReaderTaskEither";
import * as TE from "fp-ts/TaskEither";

interface Deps { readonly baseUrl: string }
interface Row { readonly id: string }
type E = { readonly tag: "LoadError"; readonly reason: string };

const fetchOnce = (url: string, id: string): TE.TaskEither<E, Row> =>
  TE.tryCatch(
    async () => {
      const r = await fetch(`${url}/rows/${id}`);
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return (await r.json()) as Row;
    },
    (u): E => ({ tag: "LoadError", reason: u instanceof Error ? u.message : String(u) }),
  );

const retry = <R, Err, A>(
  eff: RTE.ReaderTaskEither<R, Err, A>,
  attempts: number,
): RTE.ReaderTaskEither<R, Err, A> =>
  attempts <= 1 ? eff : pipe(eff, RTE.orElse(() => retry(eff, attempts - 1)));

export const load = (id: string): RTE.ReaderTaskEither<Deps, E, Row> =>
  retry(
    pipe(
      RTE.ask<Deps>(),
      RTE.chainTaskEitherK((d) => fetchOnce(d.baseUrl, id)),
    ),
    3,
  );
