class TimeoutError extends Data.TaggedError("TimeoutError")<{ readonly ms: number }> {}

export const runWithTimeout = <A, E, R>(
  eff: Effect.Effect<A, E, R>,
  ms: number,
): Effect.Effect<A, E | TimeoutError, R> =>
  Effect.race(
    eff,
    Effect.flatMap(Effect.sleep(Duration.millis(ms)), () =>
      Effect.fail(new TimeoutError({ ms })),
